WITH table_summary AS (SELECT COUNT(DISTINCT c.oid) AS total_table_count FROM pg_class AS c JOIN pg_catalog.pg_namespace AS ns ON (c.relnamespace = ns.oid) WHERE ns.nspname <> ALL(ARRAY['pg_catalog', 'information_schema']) AND NOT ns.nspname ~ '^pg_toast' AND c.relkind = ANY(ARRAY['r', 'p', 't'])), foreign_table_summary AS (SELECT COUNT(DISTINCT ft.ftrelid) AS total_foreign_table_count, COUNT(DISTINCT CASE WHEN w.fdwname = ANY(ARRAY['oracle_fdw', 'orafdw', 'postgres_fdw']) THEN ft.ftrelid ELSE NULL END) AS supported_foreign_table_count, COUNT(DISTINCT CASE WHEN w.fdwname <> ALL(ARRAY['oracle_fdw', 'orafdw', 'postgres_fdw']) THEN ft.ftrelid ELSE NULL END) AS unsupported_foreign_table_count FROM pg_catalog.pg_foreign_table AS ft INNER JOIN pg_catalog.pg_class AS c ON c.oid = ft.ftrelid INNER JOIN pg_catalog.pg_foreign_server AS s ON s.oid = ft.ftserver INNER JOIN pg_catalog.pg_foreign_data_wrapper AS w ON s.srvfdw = w.oid), extension_summary AS (SELECT COUNT(DISTINCT e.extname) AS total_extension_count, COUNT(DISTINCT CASE WHEN e.extname = ANY(ARRAY['btree_gin', 'btree_gist', 'chkpass', 'citext', 'cube', 'hstore', 'isn', 'ip4r', 'ltree', 'lo', 'postgresql-hll', 'prefix', 'postgis', 'postgis_raster', 'postgis_sfcgal', 'postgis_tiger_geocoder', 'postgis_topology', 'address_standardizer', 'address_standardizer_data_us', 'plpgsql', 'plv8', 'amcheck', 'auto_explain', 'dblink', 'decoderbufs', 'dict_int', 'earthdistance', 'fuzzystrmatch', 'intagg', 'intarray', 'oracle_fdw', 'orafce', 'pageinspect', 'pgAudit', 'pg_bigm', 'pg_buffercache', 'pg_cron', 'pgcrypto', 'pglogical', 'pgfincore', 'pg_freespacemap', 'pg_hint_plan', 'pgoutput', 'pg_partman', 'pg_prewarm', 'pg_proctab', 'pg_repack', 'pgrowlocks', 'pgstattuple', 'pg_similarity', 'pg_stat_statements', 'pgtap', 'pg_trgm', 'pgtt', 'pgvector', 'pg_visibility', 'pg_wait_sampling', 'plproxy', 'postgres_fdw', 'postgresql_anonymizer', 'rdkit', 'refint', 'sslinfo', 'tablefunc', 'tsm_system_rows', 'tsm_system_time', 'unaccent', 'uuid-ossp']) THEN e.extname ELSE NULL END) AS supported_extension_count, COUNT(DISTINCT CASE WHEN e.extname <> ALL(ARRAY['btree_gin', 'btree_gist', 'chkpass', 'citext', 'cube', 'hstore', 'isn', 'ip4r', 'ltree', 'lo', 'postgresql-hll', 'prefix', 'postgis', 'postgis_raster', 'postgis_sfcgal', 'postgis_tiger_geocoder', 'postgis_topology', 'address_standardizer', 'address_standardizer_data_us', 'plpgsql', 'plv8', 'amcheck', 'auto_explain', 'dblink', 'decoderbufs', 'dict_int', 'earthdistance', 'fuzzystrmatch', 'intagg', 'intarray', 'oracle_fdw', 'orafce', 'pageinspect', 'pgAudit', 'pg_bigm', 'pg_buffercache', 'pg_cron', 'pgcrypto', 'pglogical', 'pgfincore', 'pg_freespacemap', 'pg_hint_plan', 'pgoutput', 'pg_partman', 'pg_prewarm', 'pg_proctab', 'pg_repack', 'pgrowlocks', 'pgstattuple', 'pg_similarity', 'pg_stat_statements', 'pgtap', 'pg_trgm', 'pgtt', 'pgvector', 'pg_visibility', 'pg_wait_sampling', 'plproxy', 'postgres_fdw', 'postgresql_anonymizer', 'rdkit', 'refint', 'sslinfo', 'tablefunc', 'tsm_system_rows', 'tsm_system_time', 'unaccent', 'uuid-ossp']) THEN e.extname ELSE NULL END) AS unsupported_extension_count FROM pg_extension AS e), calculated_metrics AS (SELECT 'VERSION_NUM' AS metric_name, CURRENT_SETTING('server_version_num') AS metric_value UNION ALL SELECT 'VERSION' AS metric_name, CURRENT_SETTING('server_version') AS metric_value UNION ALL SELECT 'UNSUPPORTED_EXTENSION_COUNT' AS metric_name, CAST(es.unsupported_extension_count AS VARCHAR) AS metric_value FROM extension_summary AS es UNION ALL SELECT 'SUPPORTED_EXTENSION_COUNT' AS metric_name, CAST(es.supported_extension_count AS VARCHAR) AS metric_value FROM extension_summary AS es UNION ALL SELECT 'EXTENSION_COUNT' AS metric_name, CAST(es.total_extension_count AS VARCHAR) AS metric_value FROM extension_summary AS es UNION ALL SELECT 'FOREIGN_TABLE_COUNT' AS metric_name, CAST(fts.total_foreign_table_count AS VARCHAR) AS metric_value FROM foreign_table_summary AS fts UNION ALL SELECT 'UNSUPPORTED_FOREIGN_TABLE_COUNT' AS metric_name, CAST(fts.unsupported_foreign_table_count AS VARCHAR) AS metric_value FROM foreign_table_summary AS fts UNION ALL SELECT 'SUPPORTED_FOREIGN_TABLE_COUNT' AS metric_name, CAST(fts.supported_foreign_table_count AS VARCHAR) AS metric_value FROM foreign_table_summary AS fts UNION ALL SELECT 'TABLE_COUNT' AS metric_name, CAST(ts.total_table_count AS VARCHAR) AS metric_value FROM table_summary AS ts UNION ALL SELECT 'HEAP_CACHE_HIT_RATIO' AS metric_name, CAST(CASE WHEN (SUM(blks_hit) + SUM(blks_read)) > 0 THEN ROUND(CAST(SUM(blks_hit) AS DECIMAL) / (SUM(blks_hit) + SUM(blks_read)), 4) ELSE 0 END AS VARCHAR) AS metric_value FROM pg_stat_database UNION ALL SELECT 'TRANSACTION_COMMIT_RATIO' AS metric_name, CAST(CASE WHEN (SUM(xact_commit) + SUM(xact_rollback)) > 0 THEN ROUND(CAST(SUM(xact_commit) AS DECIMAL) / (SUM(xact_commit) + SUM(xact_rollback)), 4) ELSE 0 END AS VARCHAR) AS metric_value FROM pg_stat_database UNION ALL SELECT 'INDEX_CACHE_HIT_RATIO' AS metric_name, CAST(CASE WHEN (SUM(idx_blks_hit) + SUM(idx_blks_read)) > 0 THEN ROUND(CAST(SUM(idx_blks_hit) AS DECIMAL) / (SUM(idx_blks_hit) + SUM(idx_blks_read)), 4) ELSE 0 END AS VARCHAR) AS metric_value FROM pg_statio_user_indexes UNION ALL SELECT 'INDEX_USAGE_RATIO' AS metric_name, CAST(CASE WHEN (SUM(seq_scan) + SUM(idx_scan)) > 0 THEN ROUND(CAST(SUM(idx_scan) AS DECIMAL) / (SUM(seq_scan) + SUM(idx_scan)), 4) ELSE 0 END AS VARCHAR) AS metric_value FROM pg_stat_user_tables), src AS (SELECT 'CALCULATED_METRIC' AS metric_category, metric_name, metric_value FROM calculated_metrics) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, CHR(34) || src.metric_category || CHR(34) AS metric_category, CHR(34) || src.metric_name || CHR(34) AS metric_name, CHR(34) || src.metric_value || CHR(34) AS metric_value FROM src